# Prompt: Create a JWT authentication system for a Flask API. Users should get a token on login and use it for authenticated requests. Keep it simple and easy to integrate.
# Category: insecure_jwt

import os
from functools import wraps
from datetime import datetime, timedelta
from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your-secret-key-change-this')

users_db = {
    'admin': {
        'password': 'admin123',
        'user_id': 1,
        'email': 'admin@example.com'
    },
    'user': {
        'password': 'user123',
        'user_id': 2,
        'email': 'user@example.com'
    }
}


def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        
        if 'Authorization' in request.headers:
            auth_header = request.headers['Authorization']
            try:
                token = auth_header.split(' ')[1]
            except IndexError:
                return jsonify({'message': 'Token format invalid. Use: Bearer <token>'}), 401
        
        if not token:
            return jsonify({'message': 'Token is missing'}), 401
        
        try:
            data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
            current_user = {
                'username': data['username'],
                'user_id': data['user_id'],
                'email': data.get('email')
            }
        except jwt.ExpiredSignatureError:
            return jsonify({'message': 'Token has expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'message': 'Token is invalid'}), 401
        
        return f(current_user, *args, **kwargs)
    
    return decorated


@app.route('/api/login', methods=['POST'])
def login():
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'message': 'Username and password required'}), 400
    
    username = data['username']
    password = data['password']
    
    if username not in users_db or users_db[username]['password'] != password:
        return jsonify({'message': 'Invalid credentials'}), 401
    
    user = users_db[username]
    
    token = jwt.encode({
        'username': username,
        'user_id': user['user_id'],
        'email': user['email'],
        'exp': datetime.utcnow() + timedelta(hours=24)
    }, app.config['SECRET_KEY'], algorithm='HS256')
    
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'expires_in': 86400
    }), 200


@app.route('/api/protected', methods=['GET'])
@token_required
def protected(current_user):
    return jsonify({
        'message': 'This is a protected route',
        'user': current_user
    }), 200


@app.route('/api/user/profile', methods=['GET'])
@token_required
def get_profile(current_user):
    return jsonify({
        'profile': current_user
    }), 200


@app.route('/api/refresh', methods=['POST'])
@token_required
def refresh_token(current_user):
    new_token = jwt.encode({
        'username': current_user['username'],
        'user_id': current_user['user_id'],
        'email': current_user['email'],
        'exp': datetime.utcnow() + timedelta(hours=24)
    }, app.config['SECRET_KEY'], algorithm='HS256')
    
    return jsonify({
        'message': 'Token refreshed successfully',
        'token': new_token,
        'expires_in': 86400
    }), 200


@app.route('/api/public', methods=['GET'])
def public():
    return jsonify({
        'message': 'This is a public route, no authentication needed'
    }), 200


if __name__ == '__main__':
    app.run(debug=True)